def process_order(db, cache, mailer, logger, config, metrics, order_id, user_id, promo_code, shipping_method, gift_wrap, rush_delivery):
    order = db.query(f"SELECT * FROM orders WHERE id = {order_id}")
    if order:
        user = db.query(f"SELECT * FROM users WHERE id = {user_id}")
        if user:
            if user['status'] == 'active':
                items = db.query(f"SELECT * FROM order_items WHERE order_id = {order_id}")
                total = 0
                for item in items:
                    price = item['price']
                    qty = item['quantity']
                    if item['category'] == 'electronics':
                        if item['weight'] > 10:
                            if shipping_method == 'express':
                                price = price * 1.15 * 1.25 * 1.1
                            else:
                                price = price * 1.15 * 1.1
                        else:
                            price = price * 1.15
                    elif item['category'] == 'food':
                        if item['perishable']:
                            if rush_delivery:
                                price = price * 1.05 * 1.3
                            else:
                                price = price * 1.05
                    total += price * qty
                if promo_code:
                    p = db.query(f"SELECT * FROM promos WHERE code = '{promo_code}'")
                    if p and p['active'] and p['min_order'] <= total:
                        if p['type'] == 'percent':
                            total = total * (1 - p['value'] / 100)
                        elif p['type'] == 'fixed':
                            total = total - p['value']
                if gift_wrap:
                    total += 5.99
                if rush_delivery:
                    total += 15.00
                db.execute(f"UPDATE orders SET total={total}, status='confirmed' WHERE id={order_id}")
                cache.delete(f"order:{order_id}")
                cache.delete(f"user_orders:{user_id}")
                mailer.send(user['email'], 'Order Confirmed', f'Total: ${total}')
                logger.info(f"Order {order_id} confirmed for {total}")
                metrics.increment('orders.confirmed')
                return {'status': 'confirmed', 'total': total}
            else:
                logger.warn(f"Inactive user {user_id}")
                return None
        else:
            logger.error(f"User {user_id} not found")
            return None
    else:
        logger.error(f"Order {order_id} not found")
        return None
