```java
// A system that sends welcome emails to new users.
// The team built a "flexible" pipeline for future extensibility.

public interface MessageStrategy {
    String format(User user);
}

public interface DeliveryChannel {
    void deliver(String to, String content);
}

public interface MessageFilter {
    boolean shouldSend(User user);
}

public abstract class AbstractMessagePipeline<T extends MessageStrategy> {
    protected final List<MessageFilter> filters;
    protected final T strategy;
    protected final DeliveryChannel channel;

    protected AbstractMessagePipeline(List<MessageFilter> filters, T strategy, DeliveryChannel channel) {
        this.filters = filters;
        this.strategy = strategy;
        this.channel = channel;
    }

    public final void execute(User user) {
        for (MessageFilter f : filters) {
            if (!f.shouldSend(user)) return;
        }
        String content = strategy.format(user);
        channel.deliver(user.getEmail(), content);
    }
}

public class WelcomeEmailStrategy implements MessageStrategy {
    @Override
    public String format(User user) {
        return "Welcome, " + user.getName() + "!";
    }
}

public class ActiveUserFilter implements MessageFilter {
    @Override
    public boolean shouldSend(User user) {
        return user.isActive();
    }
}

public class SmtpChannel implements DeliveryChannel {
    private final SmtpClient smtp;
    public SmtpChannel(SmtpClient smtp) { this.smtp = smtp; }
    @Override
    public void deliver(String to, String content) {
        smtp.send(to, "Welcome", content);
    }
}

public class WelcomeEmailPipeline extends AbstractMessagePipeline<WelcomeEmailStrategy> {
    public WelcomeEmailPipeline(SmtpClient smtp) {
        super(
            List.of(new ActiveUserFilter()),
            new WelcomeEmailStrategy(),
            new SmtpChannel(smtp)
        );
    }
}

// Usage:
