type Order struct {
	ID        int64
	Items     []LineItem
	Status    OrderStatus
	CreatedAt time.Time
}

func (o *Order) Cancel(now time.Time) error {
	switch o.Status {
	case StatusPending:
		o.Status = StatusCancelled
		return nil
	case StatusShipped:
		o.Status = StatusReturnRequested
		return nil
	case StatusDelivered:
		if now.Sub(o.CreatedAt) > 30*24*time.Hour {
			return ErrReturnWindowExpired
		}
		o.Status = StatusReturnRequested
		return nil
	default:
		return fmt.Errorf("cannot cancel order in status %s", o.Status)
	}
}

func (o *Order) Total() Money {
	subtotal := NewMoney(0)
	for _, item := range o.Items {
		subtotal = subtotal.Add(item.LineTotal())
	}
	return subtotal.WithBulkDiscount(len(o.Items)).WithTax()
}
