}

type FXService struct {
	provider ExchangeRateProvider
}

func (s *FXService) Quote(ctx context.Context, base, target string, amount decimal.Decimal) (decimal.Decimal, error) {
	rates, err := s.provider.Latest(ctx, base)
	if err != nil {
		return decimal.Zero, fmt.Errorf("fetch exchange rates: %w", err)
	}

	rate, ok := rates[target]
	if !ok {
		return decimal.Zero, ErrUnsupportedCurrency
	}

	return amount.Mul(rate), nil
}
