  | { type: 'payment_intent.payment_failed'; payload: PaymentIntent }
  | { type: 'charge.refunded'; payload: Charge };

export async function handleStripeWebhook(event: StripeWebhookEvent, service: BillingService) {
  switch (event.type) {
    case 'payment_intent.succeeded':
      return service.recordSuccessfulPayment(event.payload);
    case 'payment_intent.payment_failed':
      return service.recordFailedPayment(event.payload);
    case 'charge.refunded':
      return service.recordRefund(event.payload);
    default:
      return assertNever(event);
  }
